type = 'BUY'; canOpen = false; canClose = false;

// === MACD Calculation ===
function ema(arr, period) {
    let k = 2 / (period + 1);
    let emaArr = [arr[0]];
    for (let j = 1; j < arr.length; j++) {
        emaArr.push(arr[j] * k + emaArr[j - 1] * (1 - k));
    }
    return emaArr;
}

if (i >= 50) {
    // Collect closing prices
    let closes = [];
    for (let j = i - 50; j <= i; j++) {
        closes.push(data?.[j]?.['close'] || 0);
    }

    // EMA 12 and EMA 26
    let ema12 = ema(closes, 12);
    let ema26 = ema(closes, 26);

    // MACD line = EMA12 - EMA26
    let macdLine = [];
    for (let j = 0; j < closes.length; j++) {
        macdLine.push(ema12[j] - ema26[j]);
    }

    // Signal line = EMA 9 of MACD line
    let signalLine = ema(macdLine, 9);

    let macdCurrent = macdLine[macdLine.length - 1];
    let macdPrev = macdLine[macdLine.length - 2];
    let signalCurrent = signalLine[signalLine.length - 1];
    let signalPrev = signalLine[signalLine.length - 2];
    let histogram = macdCurrent - signalCurrent;
    let histogramPrev = macdPrev - signalPrev;

    // === RSI Calculation (14 period) ===
    let rsiPeriod = 14;
    let gains = 0;
    let losses = 0;
    for (let j = i - rsiPeriod; j <= i; j++) {
        let diff = (data?.[j]?.['close'] || 0) - (data?.[j - 1]?.['close'] || 0);
        if (diff > 0) gains += diff;
        else losses += Math.abs(diff);
    }
    let avgGain = gains / rsiPeriod;
    let avgLoss = losses / rsiPeriod;
    let rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    let rsi = 100 - (100 / (1 + rs));

    // === LONG Strategy ===
    // Open BUY: MACD crosses above signal line AND RSI < 65 (not overbought)
    let macdBullCross = macdPrev <= signalPrev && macdCurrent > signalCurrent;
    // Close BUY: MACD crosses below signal line OR RSI > 75 (overbought)
    let macdBearCross = macdPrev >= signalPrev && macdCurrent < signalCurrent;

    // === SHORT Strategy ===
    // Open SELL: MACD crosses below signal line AND RSI > 35 (not oversold)
    // Close SELL: MACD crosses above signal line OR RSI < 25 (oversold)

    if (trend >= 0) {
        // Bullish or neutral trend -> prefer LONG
        type = 'BUY';
        canOpen = macdBullCross && rsi < 65 && rsi > 30;
        canClose = macdBearCross || rsi > 78 || (hold > 20 && histogram < histogramPrev);
    } else {
        // Bearish trend -> prefer SHORT
        type = 'SELL';
        canOpen = macdBearCross && rsi > 35 && rsi < 70;
        canClose = macdBullCross || rsi < 22 || (hold > 20 && histogram > histogramPrev);
    }
}
